// APIService.swift
class APIService {
    func executeTrade(symbol: String, quantity: Int, price: Double) async throws -> Order {
        // Perform API request to execute the trade
        let response = try await Networking.request(endpoint: "/trade", method: .post, parameters: ["symbol": symbol, "quantity": quantity, "price": price])
        return try JSONDecoder().decode(Order.self, from: response.data)
    }
}

// Order.swift
struct Order: Codable {
    let symbol: String
    let quantity: Int
    let price: Double
}

